import datasets
import pandas as pd
import numpy as np
from scipy.optimize import curve_fit

ds = datasets.load_from_disk('/app/data')
df = ds.to_pandas()

def model(D, E, B, beta):
    return E + B / ((D/1e9) ** beta)

for n0 in df['non_vocab_parameters'].unique()[:2]:
    for v in df['vocab_size'].unique()[:2]:
        sub = df[(df['non_vocab_parameters']==n0) & (df['vocab_size']==v)]
        D = sub['num_characters'].values
        L = sub['unigram_normalized_loss'].values
        try:
            popt, _ = curve_fit(model, D, L, p0=[-5, 1, 0.5])
            print(f"N={n0}, V={v} -> beta={popt[2]:.4f}, E={popt[0]:.4f}, B={popt[1]:.4f}, MSE={np.mean((L-model(D, *popt))**2):.5f}")
        except:
            pass
